import { useState } from "react";
import axios from "axios";
import { useNavigate, Link } from "react-router-dom";

export default function Register() {
  const navigate = useNavigate();

  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");

  const submit = async () => {
    try {
      await axios.post(
        "http://localhost:5000/auth/register",
        { email, password }
      );
      navigate("/login");
    } catch {
      setError("User already exists");
    }
  };

  return (
    <div className="max-w-sm mx-auto mt-24 bg-white dark:bg-gray-800 p-6 rounded-xl shadow">
      <h2 className="text-2xl font-bold mb-4 text-center">Register</h2>

      {error && (
        <p className="text-red-500 text-sm mb-3 text-center">
          {error}
        </p>
      )}

      <input
        className="w-full mb-3 px-4 py-2 rounded border dark:bg-gray-700"
        placeholder="Email"
        onChange={(e) => setEmail(e.target.value)}
      />

      <input
        type="password"
        className="w-full mb-4 px-4 py-2 rounded border dark:bg-gray-700"
        placeholder="Password"
        onChange={(e) => setPassword(e.target.value)}
      />

      <button
        onClick={submit}
        className="w-full py-2 bg-indigo-600 text-white rounded hover:bg-indigo-700"
      >
        Register
      </button>

      <p className="text-sm text-center mt-4 text-gray-500">
        Already have an account?{" "}
        <Link to="/login" className="text-indigo-600">
          Login
        </Link>
      </p>
    </div>
  );
}
